1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	
23	#define AST_MAX 64
24	
25	// AST storage (parallel arrays)
26	int node_type[AST_MAX];
27	int node_val[AST_MAX];
28	int node_left[AST_MAX];
29	int node_right[AST_MAX];
30	int node_count;
31	
32	// Parser state
33	int parse_pos;
34	int parse_err;
35	char *parse_line;   // source line for identifier lookup
36	
37	// Allocate a new AST node
38	int ast_new() {
39	    if (node_count >= AST_MAX) {
40	        parse_err = 1;
41	        return 0;
42	    }
43	    int n = node_count;
44	    node_count++;
45	    node_left[n] = -1;
46	    node_right[n] = -1;
47	    return n;
48	}
49	
50	int ast_num(int val) {
51	    int n = ast_new();
52	    node_type[n] = NODE_NUM;
53	    node_val[n] = val;
54	    return n;
55	}
56	
57	int ast_binop(int op, int left, int right) {
58	    int n = ast_new();
59	    node_type[n] = NODE_BINOP;
60	    node_val[n] = op;
61	    node_left[n] = left;
62	    node_right[n] = right;
63	    return n;
64	}
65	
66	int ast_neg(int operand) {
67	    int n = ast_new();
68	    node_type[n] = NODE_NEG;
69	    node_right[n] = operand;
70	    return n;
71	}
72	
73	int ast_ident(int sym_idx) {
74	    int n = ast_new();
75	    node_type[n] = NODE_IDENT;
76	    node_val[n] = sym_idx;
77	    return n;
78	}
79	
80	int ast_assign(int sym_idx, int expr) {
81	    int n = ast_new();
82	    node_type[n] = NODE_ASSIGN;
83	    node_val[n] = sym_idx;
84	    node_right[n] = expr;
85	    return n;
86	}
87	
88	int ast_vec(int heap_idx) {
89	    int n = ast_new();
90	    node_type[n] = NODE_VEC;
91	    node_val[n] = heap_idx;
92	    return n;
93	}
94	
95	int ast_monad(int res_id, int operand) {
96	    int n = ast_new();
97	    node_type[n] = NODE_MONAD;
98	    node_val[n] = res_id;
99	    node_right[n] = operand;
100	    return n;
101	}
102	
103	int ast_dyad(int res_id, int left, int right) {
104	    int n = ast_new();
105	    node_type[n] = NODE_DYAD;
106	    node_val[n] = res_id;
107	    node_left[n] = left;
108	    node_right[n] = right;
109	    return n;
110	}
111	
112	int ast_reduce(int op, int operand) {
113	    int n = ast_new();
114	    node_type[n] = NODE_REDUCE;
115	    node_val[n] = op;
116	    node_right[n] = operand;
117	    return n;
118	}
119	
120	// Check if a reserved word can be used dyadically
121	int is_dyadic_res(int res_id) {
122	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT;
123	}
124	
125	// Temporary buffer for collecting strand elements
126	int strand_buf[64];
127	
128	int is_binop(int ty) {
129	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH;
130	}
131	
132	// Combined parse function avoids mutual recursion.
133	// mode 0 = expression, mode 1 = value only
