1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
12	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
13	int qled_shadow;
14	
15	// Apply a binary op to two scalars
16	int eval_binop_scalar(int op, int a, int b) {
17	    if (op == TOK_PLUS)       return a + b;
18	    if (op == TOK_MINUS)      return a - b;
19	    if (op == TOK_STAR)       return a * b;
20	    if (op == TOK_SLASH) {
21	        if (b == 0) { eval_err = 1; return 0; }
22	        return a / b;
23	    }
24	    eval_err = 1;
25	    return 0;
26	}
27	
28	// Evaluate AST node, return heap index of result array.
29	// On error, sets eval_err and returns -1.
30	int eval(int n) {
31	    if (eval_err) return -1;
32	    if (n < 0 || n >= node_count) {
33	        eval_err = 1;
34	        return -1;
35	    }
36	
37	    int ty = node_type[n];
38	
39	    if (ty == NODE_NUM) {
40	        int r = arr_scalar(node_val[n]);
41	        if (r < 0) { eval_err = 5; return -1; }
42	        return r;
43	    }
44	
45	    if (ty == NODE_VEC) {
46	        return node_val[n];
47	    }
48	
49	    if (ty == NODE_IDENT) {
50	        int idx = node_val[n];
51	        if (!sym_set_flag[idx]) {
52	            eval_err = 2;
53	            return -1;
54	        }
55	        return sym_val[idx];
56	    }
57	
58	    if (ty == NODE_ASSIGN) {
59	        int idx = node_val[n];
60	        int v = eval(node_right[n]);
61	        if (eval_err) return -1;
62	        sym_val[idx] = v;
63	        sym_set_flag[idx] = 1;
64	        return v;
65	    }
66	
67	    if (ty == NODE_QOUT) {
68	        int v = eval(node_right[n]);
69	        if (eval_err) return -1;
70	        return v;
71	    }
72	
73	    if (ty == NODE_QLED) {
74	        // Read LED D2 from shadow register (1=on, 0=off)
75	        int r = arr_scalar(qled_shadow);
76	        if (r < 0) { eval_err = 5; return -1; }
77	        return r;
78	    }
79	
80	    if (ty == NODE_QLED_ASSIGN) {
81	        int v = eval(node_right[n]);
82	        if (eval_err) return -1;
83	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
84	        int val = arr_get(v, 0) & 1;
85	        qled_shadow = val;
86	        // Write LED D2: invert bit 0 (active-low: 1=on writes 0)
87	        *(char *)0xFF0000 = val ^ 1;
88	        return v;
89	    }
90	
91	    if (ty == NODE_NEG) {
92	        int v = eval(node_right[n]);
93	        if (eval_err) return -1;
94	        int rk = arr_rank(v);
95	        if (rk == 0) {
96	            int r = arr_scalar(0 - arr_get(v, 0));
97	            if (r < 0) { eval_err = 5; return -1; }
98	            return r;
99	        }
100	        // Negate each element of vector
101	        if (rk == 1) {
102	            int sz = arr_size(v);
103	            int r = arr_vector(sz);
104	            if (r < 0) { eval_err = 5; return -1; }
105	            int i = 0;
106	            while (i < sz) {
107	                arr_set(r, i, 0 - arr_get(v, i));
108	                i++;
109	            }
110	            return r;
111	        }
112	        // Negate each element of matrix
113	        if (rk == 2) {
114	            int d0 = arr_dim0(v);
115	            int d1 = arr_dim1(v);
116	            int sz = d0 * d1;
117	            int r = arr_new(2, d0, d1);
118	            if (r < 0) { eval_err = 5; return -1; }
119	            int i = 0;
120	            while (i < sz) {
121	                arr_set(r, i, 0 - arr_get(v, i));
122	                i++;
123	            }
124	            return r;
125	        }
126	        eval_err = 4;
127	        return -1;
128	    }
129	
130	    if (ty == NODE_MONAD) {
131	        int v = eval(node_right[n]);
132	        if (eval_err) return -1;
133	        int res_id = node_val[n];
134	
135	        if (res_id == RES_IOTA) {
136	            // iota N: generate vector 0 1 2 ... N-1
137	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
138	            int count = arr_get(v, 0);
139	            if (count < 0) { eval_err = 1; return -1; }
140	            int r = arr_vector(count);
141	            if (r < 0) { eval_err = 5; return -1; }
142	            int i = 0;
143	            while (i < count) {
144	                arr_set(r, i, i);
145	                i++;
146	            }
147	            return r;
148	        }
149	
150	        if (res_id == RES_RHO) {
151	            // rho A: return shape of A
152	            int rk = arr_rank(v);
153	            if (rk == 0) {
154	                // Scalar: shape is empty vector
155	                int r = arr_vector(0);
156	                if (r < 0) { eval_err = 5; return -1; }
157	                return r;
158	            }
159	            if (rk == 1) {
160	                // Vector: shape is 1-element vector with length
161	                int r = arr_scalar(arr_dim0(v));
162	                if (r < 0) { eval_err = 5; return -1; }
163	                return r;
164	            }
165	            if (rk == 2) {
166	                // Matrix: shape is 2-element vector (rows cols)
167	                int r = arr_vector(2);
168	                if (r < 0) { eval_err = 5; return -1; }
169	                arr_set(r, 0, arr_dim0(v));
170	                arr_set(r, 1, arr_dim1(v));
171	                return r;
172	            }
173	            eval_err = 4;
174	            return -1;
175	        }
176	
177	        if (res_id == RES_REV) {
178	            // rev A: reverse a vector
179	            int rk = arr_rank(v);
180	            if (rk == 0) {
181	                // Scalar: reverse is identity
182	                return v;
183	            }
184	            if (rk == 1) {
185	                int sz = arr_size(v);
186	                int r = arr_vector(sz);
187	                if (r < 0) { eval_err = 5; return -1; }
