#define TOK_STAR    5   // *
#define TOK_SLASH   6   // /
#define TOK_LPAREN  7   // (
#define TOK_RPAREN  8   // )
#define TOK_ASSIGN  9   // <-
#define TOK_RES    10   // reserved word (ID in tok_val)
#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
#define TOK_QLED   12   // qled — LED D2 hardware I/O
#define TOK_QSW    13   // qsw — switch S2 hardware I/O (read-only)

// Reserved word IDs
#define RES_RHO     0
#define RES_IOTA    1
#define RES_TAKE    2
#define RES_DROP    3
#define RES_REV     4
#define RES_CAT     5

